sql:
SELECT company_name, license_number
FROM insurance_companies
WHERE company_id IN (
  SELECT company_id
  FROM insurance_rates
  WHERE rate < (
    SELECT AVG(rate)
    FROM insurance_rates
  )
);

SELECT `user_id`
FROM `rate_updates`
WHERE `new_rate` > `previous_rate` AND `user_id` = 1;

SELECT DISTINCT company_name
FROM insurance_companies
ORDER BY rating DESC;

external_knowledge:
- "heaviest financial anchor" means the highest insurance rate;
- "prime of their lives" here refers to being within the age range of 25 to 35;
- "earning between $40,000 and $60,000 a year" is the income bracket for the demographic;
- "having been married" means the demographic's marital status is 'Married'.

